class Shape {
public:
    virtual double area() {
        return 0;
    }
};
class Circle : public Shape {
public:
    double radius;
    Circle(double r) : radius(r) {}
    double area() override {
        return 3.14 * radius * radius;
    }
};
class Square : public Shape {
public:
    double side;
    Square(double s) : side(s) {}
    double area() override {
        return side * side;
    }
};

double totalArea(Shape* shapes[], int count) {
    double total = 0;
    for (int i = 0; i < count; i++) {
        total += shapes[i]->area();
    }
    return total;
}

Shape* shapes[2] = { new Circle(1), new Square(2) };
cout << totalArea(shapes, 2);

